# GitHub APK workflow-এ অনলাইন বাংলা অনুবাদের জন্য INTERNET permission যোগ করুন।
wf=ROOT/'.github/workflows/android-apk.yml'
if wf.exists():
    s=wf.read_text(encoding='utf-8'); before=s
    if 'Enable internet for Bengali translation' not in s and '      - name: Get dependencies\n' in s:
        permission_step="""      - name: Enable internet for Bengali translation
        run: |
          python3 - <<'PY'
          from pathlib import Path
          p = Path('android/app/src/main/AndroidManifest.xml')
          text = p.read_text()
          permission = '<uses-permission android:name="android.permission.INTERNET" />'
          if permission not in text:
              text = text.replace('<manifest xmlns:android="http://schemas.android.com/apk/res/android">', '<manifest xmlns:android="http://schemas.android.com/apk/res/android">\\n    ' + permission)
              p.write_text(text)
          PY

"""
        s=s.replace('      - name: Get dependencies\n', permission_step+'      - name: Get dependencies\n',1)
    if s!=before:
        wf.write_text(s,encoding='utf-8'); changed.append('.github/workflows/android-apk.yml')

